\log  \mathbb {P}_{\theta }(\mathcal {H}, \xi ) &= \log  \left [p(s_{0})\delta _{\{b_{0} = 1\}}\eta _{\theta }(z_{0} \mid  s_{0}) \prod _{t=1}^{T - 1} \mathbb {P}_{\theta }(b_t, z_t \mid  z_{t - 1}, s_t) \prod _{t = 0}^{T - 1} \pi _{\theta }(a_t \mid  s_t, z_t) p(s_{t+1} \mid  s_t, a_t)\right ] \\
&= \log  p(s_{0})\delta _{\{b_{0} = 1\}} + \log \left [\eta _{\theta }(z_{0} \mid  s_{0}) \prod _{t=1}^{T - 1} \mathbb {P}_{\theta }(b_t, z_t \mid  z_{t - 1}, s_t) \prod _{t = 0}^{T - 1} \pi _{\theta }(a_t \mid  s_t, z_t) \right ] + \sum _{t=0}^{T-1} \log  \left [p(s_{t+1} \mid  s_t, a_t)\right ] \\
&= \underbrace {\log  p(s_{0})\delta _{\{b_{0} = 1\}} + \sum _{t=0}^{T-1} \log  \left [p(s_{t+1} \mid  s_t, a_t)\right ]}_{\text {independent of } \theta } + \log \left [\eta _{\theta }(z_{0} \mid  s_{0}) \prod _{t=1}^{T - 1} \mathbb {P}_{\theta }(b_t, z_t \mid  z_{t - 1}, s_t) \prod _{t = 0}^{T - 1} \pi _{\theta }(a_t \mid  s_t, z_t)\right ]
.\end {align*}

